fixed_code:
use typed_arena::Arena;

fn main() {
    let arena = Arena::new();
    let mut vec = Vec::with_capacity(10);
    for i in 0..10 {
        vec.push(*arena.alloc(i));
    }
    for data in &vec {
        println!("{}", *data);
    }
}
